import zipfile
from lxml import etree
W='{http://schemas.openxmlformats.org/wordprocessingml/2006/main}'
with zipfile.ZipFile('work/markup_intermediate.docx') as z:
    data = z.read('word/document.xml')
root = etree.fromstring(data)
body = root.find(f'{W}body')

def render(p):
    out=[]
    for child in p.iter():
        tag=child.tag.replace(W,'w:')
        if tag=='w:ins':
            out.append('[INS:'+ ''.join((t.text or '') for t in child.iter(f'{W}t'))+']')
        elif tag=='w:del':
            out.append('[DEL:'+ ''.join((t.text or '') for t in child.iter(f'{W}delText'))+']')
    return ' '.join(out)

paras = body.findall(f'{W}p')
# find paragraphs by content
targets = ['fair market value of each RSU', 'states of Oregon, Washington', 'period of twenty-one (21) calendar days from the date of receipt', 'aggregate Settlement Payment under this Agreement is Five Hundred Thirty']
for p in paras:
    full = ''.join((t.text or '') for t in p.iter(f'{W}t')) + ''.join((t.text or '') for t in p.iter(f'{W}delText'))
    for tg in targets:
        if tg in full:
            print('==== TARGET:', tg[:40], '====')
            print(render(p)[:900])
            print()
            break
""}

