import zipfile, importlib.util
from lxml import etree
W='{http://schemas.openxmlformats.org/wordprocessingml/2006/main}'
spec=importlib.util.spec_from_file_location('rc','work/redline_custom.py')
rc=importlib.util.module_from_spec(spec); spec.loader.exec_module(rc)

with zipfile.ZipFile('work/markup_intermediate.docx') as z:
    data=z.read('word/document.xml')
body=etree.fromstring(data).find(f'{W}body')
with zipfile.ZipFile('documents/draft-settlement-agreement.docx') as z:
    odata=z.read('word/document.xml')
obody=etree.fromstring(odata).find(f'{W}body')
oparas=[c for c in obody if c.tag==f'{W}p']
orig_texts=[''.join((t.text or '') for t in p.iter(f'{W}t')) for p in oparas]

def accept_text(p):
    out=[]
    for r in p.iter(f'{W}r'):
        par=r.getparent()
        if par is not None and par.tag==f'{W}del': continue
        t=r.find(f'{W}t')
        if t is not None and t.text: out.append(t.text)
    return ''.join(out)
def reject_text(p):
    out=[]
    for child in p.iter():
        if child.tag==f'{W}del':
            for t in child.iter(f'{W}delText'): out.append(t.text or '')
        elif child.tag==f'{W}r':
            par=child.getparent()
            if par is not None and par.tag==f'{W}ins': continue
            t=child.find(f'{W}t')
            if t is not None and t.text: out.append(t.text)
    return ''.join(out)

paras=body.findall(f'{W}p')
# Build accept/reject maps
acc={accept_text(p) for p in paras}
rej={reject_text(p) for p in paras}
allok=True
for idx,newtext in rc.REPLACEMENTS.items():
    orig=orig_texts[idx]
    ok_a = newtext in acc
    ok_r = orig in rej
    status='OK' if (ok_a and ok_r) else 'FAIL'
    if not (ok_a and ok_r): allok=False
    print(f'para {idx}: accept==new={ok_a}  reject==orig={ok_r}  {status}')
print('ALL MODIFIED PARAGRAPHS CORRECT:', allok)
""}

